'use server';

import { updateTag } from 'next/cache';
import { insertPost } from '../lib/posts';

export type CreatePostState = {
  error?: string;
  success?: string;
};

/**
 * Creates a post and immediately expires the posts tag.
 *
 * `updateTag` is intentional here (rather than `revalidateTag`): in a Server
 * Action it provides read-your-own-writes semantics. The next render waits for
 * a fresh value instead of serving stale cached posts.
 */
export async function createPost(
  _previousState: CreatePostState,
  formData: FormData
): Promise<CreatePostState> {
  const title = String(formData.get('title') ?? '').trim();
  const body = String(formData.get('body') ?? '').trim();

  if (!title || !body) {
    return { error: 'Title and body are required.' };
  }

  await insertPost(title, body);
  updateTag('posts');

  return { success: 'Post created.' };
}

