import { unstable_cache } from 'next/cache';

export type Post = {
  id: string;
  title: string;
  body: string;
  createdAt: string;
};

// This is deliberately kept behind a data-access function so it can be replaced
// with a database query without changing the page or the Server Action.
const posts: Post[] = [
  {
    id: '1',
    title: 'Welcome',
    body: 'This is the first post.',
    createdAt: new Date(0).toISOString()
  }
];

async function readPosts(): Promise<Post[]> {
  return posts.map((post) => ({ ...post }));
}

/** The posts query is cached and associated with the `posts` cache tag. */
export const getPosts = unstable_cache(readPosts, ['posts-list'], {
  tags: ['posts']
});

export async function insertPost(title: string, body: string): Promise<Post> {
  const post: Post = {
    id: crypto.randomUUID(),
    title,
    body,
    createdAt: new Date().toISOString()
  };

  posts.unshift(post);
  return post;
}

